mapper.select:
select c.id, c.name as name,c.room,e.name as masterName,c.begin_date ,c.end_date , c.create_time,c.update_time from clazz as c left join emp as e on c.master_id = e.id


        and c.name like concat('%', #{name}, '%')


        and c.begin_date >= #{begin}


        and c.end_date <= #{end}


order by c.update_time desc
limit #{start}, #{pageSize}
